import { UUID } from './common';

export enum SLASeverity {
  Breached = 'breached', // Đã vi phạm
  Danger = 'danger', // < 10% thời gian còn lại
  Warning = 'warning', // 10-25% thời gian còn lại
  Watch = 'watch', // 25-50% thời gian còn lại
}

export enum SLAAlertType {
  Ticket = 'ticket',
  Task = 'task',
}

export interface SLAAlert {
  id: UUID;
  type: SLAAlertType;
  relatedId: UUID; // ticket ID or task ID
  relatedNumber: string; // TKT-xxx or TSK-xxx
  title: string;
  severity: SLASeverity;
  assigneeId: UUID;
  assigneeName: string;
  assigneeAvatar?: string;
  departmentId: UUID;
  departmentName: string;
  priority: 'low' | 'medium' | 'high' | 'critical';
  
  // SLA timing
  slaDeadline: string; // ISO timestamp
  slaMinutesRemaining: number; // Negative if breached
  slaPercentRemaining: number; // Percentage of time remaining (can be negative)
  
  // Metadata
  createdAt: string;
  firstResponseTime?: string;
  escalationLevel: number; // 0 = no escalation, 1+ = escalated
  escalatedAt?: string;
  escalatedBy?: UUID;
  
  // Additional context
  description?: string;
  lastActivityAt: string;
}

export interface SLAStats {
  breached: number;
  danger: number;
  warning: number;
  watch: number;
  complianceRate: number; // Percentage
  totalActive: number;
}

export interface SLAAlertFilters {
  severity?: SLASeverity | 'all';
  type?: SLAAlertType | 'all';
  departmentId?: UUID | 'all';
  assigneeId?: UUID;
  searchQuery?: string;
}

export interface EscalateRequest {
  alertId: UUID;
  reason: string;
  escalateTo?: UUID; // User ID to escalate to
}

export interface ReassignAlertRequest {
  alertId: UUID;
  relatedId: UUID; // ticket or task ID
  type: SLAAlertType;
  newAssigneeId: UUID;
  newAssigneeName: string;
  reason: string;
}

export interface CandidateSuggestion {
  userId: UUID;
  userName: string;
  userAvatar?: string;
  departmentName: string;
  currentWorkload: number;
  skillMatch: number; // 0-100
  availabilityScore: number; // 0-100
  avgResponseTime: number; // minutes
}
