import React, { useEffect, useState, useRef } from 'react';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import { switchCompany } from '../../../store/slices/authSlice';
import { addToast } from '../../../store/slices/uiSlice';
import { companyService, ActiveCompanyItem } from '../../../services/companyService';
import { Modal } from '../../common/Modal';
import styles from './SwitchCompanyModal.module.css';

export interface SwitchCompanyModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const SwitchCompanyModal: React.FC<SwitchCompanyModalProps> = ({ isOpen, onClose }) => {
  const dispatch = useAppDispatch();
  const currentUser = useAppSelector((state) => state.auth.user);
  const loading = useAppSelector((state) => state.auth.loading);

  const [companies, setCompanies] = useState<ActiveCompanyItem[]>([]);
  const [fetchLoading, setFetchLoading] = useState(false);
  const [selectedId, setSelectedId] = useState<string>('');
  const fetchedRef = useRef(false);

  // Load active companies once when modal opens
  useEffect(() => {
    if (!isOpen) return;

    // Reset selection to current company when modal opens
    setSelectedId(currentUser?.companyId ?? '');

    if (fetchedRef.current) return;
    fetchedRef.current = true;

    const timer = setTimeout(() => {
      setFetchLoading(true);
      companyService
        .getActiveList()
        .then(setCompanies)
        .catch(() => {
          dispatch(addToast({ message: 'Không thể tải danh sách công ty.', type: 'error' }));
        })
        .finally(() => setFetchLoading(false));
    }, 0);

    return () => clearTimeout(timer);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  const handleSwitch = async () => {
    if (!selectedId || selectedId === currentUser?.companyId) {
      onClose();
      return;
    }

    const result = await dispatch(switchCompany(selectedId));
    if (switchCompany.fulfilled.match(result)) {
      dispatch(addToast({ message: 'Đã chuyển đổi công ty thành công.', type: 'success' }));
      onClose();
      // Reload page to reset all tenant-scoped data in Redux slices
      window.location.reload();
    } else {
      dispatch(addToast({ message: 'Chuyển đổi công ty thất bại.', type: 'error' }));
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Chuyển đổi công ty" size="sm">
      <div className={styles.body}>
        {fetchLoading ? (
          <div className={styles.loadingText}>Đang tải danh sách công ty...</div>
        ) : (
          <>
            <p className={styles.hint}>Chọn công ty bạn muốn làm việc:</p>
            <ul className={styles.companyList}>
              {companies.map((c) => (
                <li
                  key={c.id}
                  className={`${styles.companyItem} ${selectedId === c.id ? styles.selected : ''}`}
                  onClick={() => setSelectedId(c.id)}
                  role="option"
                  aria-selected={selectedId === c.id}
                >
                  {c.logoUrl && (
                    <img src={c.logoUrl} alt={c.name} className={styles.logo} />
                  )}
                  <span className={styles.companyName}>
                    {c.shortName ? `${c.shortName} — ` : ''}{c.name}
                  </span>
                  {selectedId === c.id && (
                    <i className={`fas fa-check ${styles.checkIcon}`} />
                  )}
                </li>
              ))}
              {companies.length === 0 && !fetchLoading && (
                <li className={styles.empty}>Không có công ty nào.</li>
              )}
            </ul>
          </>
        )}
      </div>
      <div className={styles.footer}>
        <button className={styles.cancelBtn} onClick={onClose} disabled={loading}>
          Hủy
        </button>
        <button
          className={styles.confirmBtn}
          onClick={handleSwitch}
          disabled={loading || !selectedId || selectedId === currentUser?.companyId}
        >
          {loading ? 'Đang xử lý...' : 'Chuyển đổi'}
        </button>
      </div>
    </Modal>
  );
};
