import React from 'react';
import styles from './StatsCardsGrid.module.css';

export interface StatsCardsGridProps {
  children: React.ReactNode;
  /** Number of columns in the grid. Defaults to 4. */
  columns?: number;
}

export const StatsCardsGrid: React.FC<StatsCardsGridProps> = ({ children, columns = 4 }) => {
  return (
    <div
      className={styles.grid}
      style={{ '--stats-columns': columns } as React.CSSProperties}
    >
      {children}
    </div>
  );
};
