import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { ToastProvider, ReduxToastContainer } from './components/common/Toast';
import { AlertProvider } from './components/common/Alert';
import { ProtectedRoute } from './components/auth/ProtectedRoute';
import { AppLayout } from './components/layout/AppLayout';
import UsersManagementPage from './pages/UsersManagementPage';
import CompaniesManagementPage from './pages/CompaniesManagementPage';
import DepartmentsManagementPage from './pages/DepartmentsManagementPage';
import AccountsManagementPage from './pages/AccountsManagementPage';
import PermissionsManagementPage from './pages/PermissionsManagementPage';
import DataCleanupPage from './pages/DataCleanupPage/DataCleanupPage';

const Root: React.FC = () => (
  <Provider store={store}>
    <AlertProvider>
      <ToastProvider>
        <ReduxToastContainer />
        <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
          <Routes>
            <Route
              path="/admin"
              element={
                <ProtectedRoute>
                  <AppLayout />
                </ProtectedRoute>
              }
            >
              <Route path="users" element={<UsersManagementPage />} />
              <Route path="companies" element={<CompaniesManagementPage />} />
              <Route path="departments" element={<DepartmentsManagementPage />} />
              <Route path="accounts" element={<AccountsManagementPage />} />
              <Route path="permissions" element={<PermissionsManagementPage />} />
              <Route path="data-cleanup" element={<DataCleanupPage />} />
            </Route>
          </Routes>
        </Router>
      </ToastProvider>
    </AlertProvider>
  </Provider>
);

export default Root;
