import React from 'react';
import styles from './Topbar.module.css';
import { IconButton } from '../../common/IconButton';

export interface TopbarProps {
  title: string;
  onSearch?: (query: string) => void;
  notificationCount?: number;
  onNotificationClick?: () => void;
  onMenuClick?: () => void;
  showMenuButton?: boolean;
  /** Optional slot to replace the default bell IconButton (e.g. <NotificationCenter />). */
  notificationSlot?: React.ReactNode;
  /** Optional slot rendered in the left section, between the menu button and the title (e.g. <AppSwitcher />). */
  leftSlot?: React.ReactNode;
  /** Optional slot rendered in the right section, before the notification bell (e.g. <InstallButton />). */
  rightSlot?: React.ReactNode;
}

export const Topbar: React.FC<TopbarProps> = ({
  title,
  onSearch: _onSearch,
  notificationCount = 0,
  onNotificationClick,
  onMenuClick,
  showMenuButton = false,
  notificationSlot,
  leftSlot,
  rightSlot,
}) => {
  return (
    <header className={styles.topbar}>
      <div className={styles.left}>
        {showMenuButton && (
          <IconButton
            icon="fas fa-bars"
            variant="ghost"
            ariaLabel="Mở menu"
            onClick={onMenuClick}
            className={styles.menuButton}
          />
        )}
        {leftSlot}
        <h1 className={styles.title}>{title}</h1>
      </div>
      <div className={styles.right}>
        {rightSlot}
        {notificationSlot ?? (
          <IconButton
            icon="fas fa-bell"
            variant="ghost"
            ariaLabel="Thông báo"
            badge={notificationCount > 0 ? notificationCount : undefined}
            onClick={onNotificationClick}
          />
        )}
      </div>
    </header>
  );
};
