// ─────────────────────────────────────────────────────────────────────────────

/** Detect which app is active based on current URL. */
export function getActiveApp(pathname: string): AppId {
  if (pathname.startsWith('/medical-incidents')) return 'medical-incidents';
  if (pathname.startsWith('/fall-location-warnings')) return 'medical-incidents';
  return 'task-management';
}

