/**
 * Build QLCV task-management nav sections filtered by role AND package.
 *
 * Package rules:
 *  - 'Staff'   → full role-based behaviour (Admin / Manager / Staff sections)
 *  - 'Premium' → core tasks + history + misc (no management, no admin)
 *  - 'Basic'   → tickets + settings only (patient-level access)
 *
 * Role rules (only applied when package === 'Staff'):
 *  - Admin   → core + management + history + admin + misc
 *  - Manager → core + management + history + misc
 *  - Staff   → core + history + misc
 */
export function buildTaskManagementSections(
  role: UserRole | undefined,
  approvalBadge: number,
  slaAlertsBadge: number,
  pkg: string | undefined,
  messageBadge: number = 0,
): NavSection[] {
  console.log('Building nav sections for role:', role, 'package:', pkg);

  // Dynamic core section with live message badge
  const dynamicCoreSection: NavSection = {
    ...coreTaskSection,
    items: coreTaskSection.items.map((item) =>
      item.id === 'messages' ? { ...item, badge: messageBadge } : item,
    ),
  };

  if (pkg === 'Basic') {
    return [
      {
        title: 'Menu Chính',
        items: [
          { id: 'tickets', label: 'Phiếu yêu cầu', icon: 'fas fa-ticket-alt', path: '/tickets', badge: 5 },
        ],
      },
      miscSection,
    ];
  }

  if (pkg === 'Premium') {
    return [dynamicCoreSection, historySection, miscSection];
  }

  // Staff package (default) — role-based sections
  const mgmtSection: NavSection = {
    ...managementSection,
    items: managementSection.items.map((item) => {
      if (item.id === 'approvals') return { ...item, badge: approvalBadge };
      if (item.id === 'sla-alerts') return { ...item, badge: slaAlertsBadge };
      return item;
    }),
  };

  if (role === UserRole.Admin) {
    return [dynamicCoreSection, mgmtSection, historySection, adminOnlySection, miscSection];
  }
  if (role === UserRole.Manager) {
    return [dynamicCoreSection, mgmtSection, historySection, miscSection];
  }
  // Staff (default)
  return [dynamicCoreSection, historySection, miscSection];
}

