// ─────────────────────────────────────────────────────────────────────────────
// Path-access helper
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Returns the first accessible path for a given user (role + package).
 * If the admin has set a `defaultMenuUrl` on the account, that takes priority.
 * Used as the "go home" destination after an auth error or unauthorised access.
 */
export function getHomePath(
  role: UserRole | undefined,
  pkg: string | undefined,
  defaultMenuUrl?: string | undefined,
): string {
  if (defaultMenuUrl) return defaultMenuUrl;
  const sections = buildTaskManagementSections(role, 0, 0, pkg);
  return sections[0]?.items[0]?.path ?? '/tickets';
}
/**
 * Returns true if the given path is allowed for all users regardless of role/package.
 * Used for paths that should be universally accessible (e.g. notifications).
 * @param patchname 
 * @returns 
 */
export function isAllowPathForAllUser(patchname: string){
  const allowedPaths = [
    '/notifications',
    '/messages',
  ]
  return allowedPaths.some((p) => patchname === p || patchname.startsWith(p + '/'));
}
/**
 * Returns true if `pathname` is covered by the user's menu.
 *
 * Matching rule: a menu item with path `/foo` grants access to `/foo` itself
 * and any sub-path `/foo/…`, e.g.
 *   - `/tickets`    covers `/tickets/abc-123`
 *   - `/help`       covers `/help/faq`, `/help/contact`
 *   - `/dashboard`  covers `/dashboard/manager`
 *   - `/admin/accounts` does NOT cover `/admin/users` (different prefix)
 *
 * @param role    User's role (for Manager/Admin gating)
 * @param pkg     User's service package ('Basic' | 'Premium' | 'Staff' | undefined)
 * @param pathname Current location.pathname (e.g. '/tickets/123')
 */
export function isPathAllowed(
  role: UserRole | undefined,
  pkg: string | undefined,
  pathname: string,
): boolean {
  const allowedForAll = isAllowPathForAllUser(pathname);
  if(allowedForAll) {
    return true;
  }
  const activeApp = getActiveApp(pathname);

  const sections =
    activeApp === 'medical-incidents'
      ? buildMedicalIncidentSections(role)
      : buildTaskManagementSections(role, 0, 0, pkg);

  const allowedPaths = sections.flatMap((s) => s.items.map((i) => i.path));

  return allowedPaths.some(
    (p) => pathname === p || pathname.startsWith(p + '/'),
  );
}
