/**
 * Department service facade.
 *
 * Usage:
 *   import { departmentService } from '@/services/department';
 *
 *   // List (all authenticated users)
 *   const list = await departmentService.getDepartments({ includeInactive: false });
 *
 *   // Create (admin/manager — BFF enforces the role check)
 *   const dept = await departmentService.createDepartment({ name: 'Khoa Nhi', isActive: true, sortOrder: 10 });
 */

import { departmentEndpoint } from './endpoint';
import type { GetDepartmentsParams, CreateDepartmentRequest, UpdateDepartmentRequest, ReorderItem } from './requestModel';

export const departmentService = {
  getDepartments: (params?: GetDepartmentsParams) =>
    departmentEndpoint.getDepartments(params),

  getDepartmentById: (id: string) => departmentEndpoint.getDepartmentById(id),

  createDepartment: (data: CreateDepartmentRequest) =>
    departmentEndpoint.createDepartment(data),

  updateDepartment: (id: string, data: UpdateDepartmentRequest) =>
    departmentEndpoint.updateDepartment(id, data),

  deactivateDepartment: (id: string) => departmentEndpoint.deactivateDepartment(id),

  reorderDepartments: (items: ReorderItem[]) => departmentEndpoint.reorderDepartments(items),

  // ── Stats ──────────────────────────────────────────────────────────────
  getStats: () => departmentEndpoint.getStats(),
};

export type { GetDepartmentsParams, CreateDepartmentRequest, UpdateDepartmentRequest, ReorderItem };
export type { Department } from '../../models/Department';
