/**
 * DepartmentsManagementPage
 * Admin page for listing, adding, editing and deactivating departments.
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  departmentService,
  CreateDepartmentRequest,
  UpdateDepartmentRequest,
} from '../../services/department';
import type { BffDepartmentStatsDto } from '../../services/department/responseModel';
import { Department } from '../../models/Department';
import { Slideout } from '../../components/common/Slideout';
import { TableCard, Pagination, Button } from '../../components/common';
import { useResponsive } from '../../hooks/useResponsive';
import { useAppToast } from '../../hooks/useAppToast';
import { useMinLoadingTime } from '../../hooks/useMinLoadingTime';
import { DepartmentsStatsCards } from './components/DepartmentsStatsCards';
import { DepartmentsFilters } from './components/DepartmentsFilters';
import type { DepartmentsFilterValues } from './components/DepartmentsFilters';
import { DepartmentsListSkeleton } from './components/DepartmentsListSkeleton';
import styles from './DepartmentsManagementPage.module.css';

const PAGE_SIZE = 20;

// ─────────────────────────────────────────────────────────────────────────────
// Form state
// ─────────────────────────────────────────────────────────────────────────────

interface DeptFormData {
  name:        string;
  code:        string;
  description: string;
  sortOrder:   number;
  isActive:    boolean;
}

const emptyForm: DeptFormData = {
  name:        '',
  code:        '',
  description: '',
  sortOrder:   0,
  isActive:    true,
};

// ─────────────────────────────────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────────────────────────────────

const DepartmentsManagementPage: React.FC = () => {
  const { isMobile, isTablet } = useResponsive();
  const toast = useAppToast();
  const slideoutWidth = isMobile ? '100%' : isTablet ? '480px' : '560px';

  const [departments, setDepartments]     = useState<Department[]>([]);
  const [totalCount, setTotalCount]       = useState(0);
  const [currentPage, setCurrentPage]     = useState(1);
  const [loading, setLoading]             = useState(true);
  const showLoading                       = useMinLoadingTime(loading);
  const [stats, setStats]                 = useState<BffDepartmentStatsDto>({ total: 0, active: 0, inactive: 0 });
  const [statsLoading, setStatsLoading]   = useState(true);

  const [filters, setFilters] = useState<DepartmentsFilterValues>({
    search: '', includeInactive: false,
  });

  const totalPages = Math.ceil(totalCount / PAGE_SIZE);

  // Modal
  const [modalOpen, setModalOpen]           = useState(false);
  const [editingDept, setEditingDept]       = useState<Department | null>(null);
  const [formData, setFormData]             = useState<DeptFormData>(emptyForm);
  const [formError, setFormError]           = useState<string | null>(null);
  const [saving, setSaving]                 = useState(false);

  // Deactivate confirm
  const [confirmId, setConfirmId]           = useState<string | null>(null);
  const [deactivating, setDeactivating]     = useState(false);

  // ── Load ─────────────────────────────────────────────────────────────────
  // Cancel refs prevent React StrictMode's double-invoke (dev) from applying
  // stale results and also guard against unmount races in production.
  const loadCancelRef      = useRef(false);
  const loadStatsCancelRef = useRef(false);

  const loadDepartments = useCallback(async () => {
    loadCancelRef.current = false;
    setLoading(true);
    try {
      const result = await departmentService.getDepartments({
        includeInactive: filters.includeInactive,
        search: filters.search || undefined,
        page: currentPage,
        pageSize: PAGE_SIZE,
      });
      if (loadCancelRef.current) return;
      setDepartments(result.items);
      setTotalCount(result.totalCount);
    } catch (err: unknown) {
      if (!loadCancelRef.current) toast.fromError(err, 'Không thể tải danh sách phòng ban, vui lòng thử lại');
    } finally {
      if (!loadCancelRef.current) setLoading(false);
    }
  }, [filters.search, filters.includeInactive, currentPage]);

  const loadStats = useCallback(async () => {
    loadStatsCancelRef.current = false;
    setStatsLoading(true);
    try {
      const data = await departmentService.getStats();
      if (loadStatsCancelRef.current) return;
      setStats(data);
    } catch {
      // stats errors are non-critical; page remains usable
    } finally {
      if (!loadStatsCancelRef.current) setStatsLoading(false);
    }
  }, []);

  useEffect(() => { const t = setTimeout(loadDepartments, 0); return () => { clearTimeout(t); loadCancelRef.current = true; }; }, [loadDepartments]);
  useEffect(() => { const t = setTimeout(loadStats, 0); return () => { clearTimeout(t); loadStatsCancelRef.current = true; }; }, [loadStats]);

  // ── Modal helpers ─────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditingDept(null);
    setFormData({ ...emptyForm, sortOrder: totalCount + 1 });
    setFormError(null);
    setModalOpen(true);
  };

  const openEdit = (dept: Department) => {
    setEditingDept(dept);
    setFormData({
      name:        dept.name,
      code:        dept.code ?? '',
      description: dept.description ?? '',
      sortOrder:   dept.sortOrder,
      isActive:    dept.isActive,
    });
    setFormError(null);
    setModalOpen(true);
  };

  const closeModal = () => {
    if (saving) return;
    setModalOpen(false);
    setEditingDept(null);
    setFormData(emptyForm);
    setFormError(null);
  };

  const handleFormChange = (
    field: keyof DeptFormData,
    value: string | number | boolean
  ) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setFormError(null);
  };

  const handleSave = async () => {
    if (!formData.name.trim()) { setFormError('Tên phòng ban không được để trống'); return; }

    setSaving(true);
    setFormError(null);
    try {
      if (editingDept) {
        const req: UpdateDepartmentRequest = {
          name:        formData.name.trim(),
          code:        formData.code.trim()        || undefined,
          description: formData.description.trim() || undefined,
          sortOrder:   formData.sortOrder,
          isActive:    formData.isActive,
        };
        await departmentService.updateDepartment(editingDept.id, req);
      } else {
        const req: CreateDepartmentRequest = {
          name:        formData.name.trim(),
          code:        formData.code.trim()        || undefined,
          description: formData.description.trim() || undefined,
          sortOrder:   formData.sortOrder,
          isActive:    formData.isActive,
        };
        await departmentService.createDepartment(req);
      }
      await loadDepartments();
      await loadStats();
      toast.success(editingDept ? 'Cập nhật phòng ban thành công' : 'Tạo phòng ban thành công');
      closeModal();
    } catch (err: any) {
      const message = err?.message ?? 'Đã có lỗi xảy ra. Vui lòng thử lại.';
      setFormError(message);
      toast.fromError(err, 'Đã có lỗi xảy ra. Vui lòng thử lại.');
    } finally {
      setSaving(false);
    }
  };

  // ── Deactivate ────────────────────────────────────────────────────────────

  const handleDeactivate = async () => {
    if (!confirmId) return;
    setDeactivating(true);
    try {
      await departmentService.deactivateDepartment(confirmId);
      toast.success('Vô hiệu hóa phòng ban thành công');
      await loadDepartments();
      await loadStats();
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể vô hiệu hóa phòng ban, vui lòng thử lại');
    } finally {
      setDeactivating(false);
      setConfirmId(null);
    }
  };

  // ── Render ────────────────────────────────────────────────────────────────

  const handleFilterChange = (newFilters: DepartmentsFilterValues) => {
    setFilters(newFilters);
    setCurrentPage(1);
  };

  return (
    <div className={styles.page}>
      {/* 1. Page Header */}
      <div className={styles.header}>
        <h1 className={styles.title}>
          <i className="fas fa-building" />
          Quản lý phòng ban
        </h1>
        <Button variant="primary" onClick={openCreate}>
          <i className="fas fa-plus" />
          {!isMobile && ' Thêm phòng ban'}
        </Button>
      </div>

      {/* 2. Stats Cards */}
      <DepartmentsStatsCards stats={stats} loading={showLoading || statsLoading} />

      {/* 3. TableCard: Filters + Table */}
      <TableCard
        header={<DepartmentsFilters filters={filters} onChange={handleFilterChange} />}
        footer={
          !showLoading && departments.length > 0 ? (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          ) : undefined
        }
      >
        {showLoading && <DepartmentsListSkeleton />}

        {!showLoading && departments.length === 0 && (
          <div className={styles.emptyState}>
            <i className="fas fa-building" />
            <p>Không tìm thấy phòng ban nào</p>
          </div>
        )}

        {!showLoading && departments.length > 0 && (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th className={styles.orderCol}>#</th>
                  <th>Tên phòng ban</th>
                  <th>Mã</th>
                  <th>Mô tả</th>
                  <th>Trạng thái</th>
                  <th className={styles.actionsCol}>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {departments.map((dept, idx) => (
                  <tr key={dept.id} className={!dept.isActive ? styles.inactiveRow : ''}>
                    <td className={styles.orderCell}>{(currentPage - 1) * PAGE_SIZE + idx + 1}</td>
                    <td>
                      <div className={styles.deptName}>{dept.name}</div>
                    </td>
                    <td>
                      {dept.code
                        ? <span className={styles.codeBadge}>{dept.code}</span>
                        : <span className={styles.na}>—</span>
                      }
                    </td>
                    <td className={styles.descCell}>
                      {dept.description || <span className={styles.na}>—</span>}
                    </td>
                    <td>
                      <span className={`${styles.statusBadge} ${dept.isActive ? styles.active : styles.inactive}`}>
                        {dept.isActive ? 'Hoạt động' : 'Ngừng hoạt động'}
                      </span>
                    </td>
                    <td className={styles.actionsCell}>
                      <button
                        className={styles.editBtn}
                        onClick={() => openEdit(dept)}
                        title="Chỉnh sửa"
                      >
                        <i className="fas fa-pen"></i>
                      </button>
                      {dept.isActive && (
                        <button
                          className={styles.deactivateBtn}
                          onClick={() => setConfirmId(dept.id)}
                          title="Vô hiệu hóa"
                        >
                          <i className="fas fa-ban"></i>
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </TableCard>

      {/* ── Add / Edit Slideout ── */}
      <Slideout
        isOpen={modalOpen}
        onClose={closeModal}
        title={
          <span style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <i className={editingDept ? 'fas fa-pen' : 'fas fa-plus-circle'} style={{ color: 'var(--primary-color)' }} />
            {editingDept ? 'Chỉnh sửa phòng ban' : 'Thêm phòng ban mới'}
          </span>
        }
        width={slideoutWidth}
        customFooter={
          <>
            <button className={styles.cancelBtn} onClick={closeModal} disabled={saving}>
              Hủy
            </button>
            <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
              {saving
                ? <><i className="fas fa-spinner fa-spin"></i> Đang lưu...</>
                : <><i className="fas fa-save"></i> {editingDept ? 'Cập nhật' : 'Tạo mới'}</>
              }
            </button>
          </>
        }
      >
        <div className={styles.form}>
          {formError && (
            <div className={styles.formError}>
              <i className="fas fa-exclamation-circle"></i>
              {formError}
            </div>
          )}

          <div className={styles.formGrid}>
                <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                  <label className={styles.label}>
                    Tên phòng ban <span className={styles.required}>*</span>
                  </label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.name}
                    onChange={(e) => handleFormChange('name', e.target.value)}
                    placeholder="Khoa Nội I"
                    required
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>
                    Mã phòng ban{' '}
                    <span className={styles.hint}>(tối đa 20 ký tự, không bắt buộc)</span>
                  </label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.code}
                    onChange={(e) => handleFormChange('code', e.target.value.toUpperCase())}
                    placeholder="NOI1"
                    maxLength={20}
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Thứ tự hiển thị</label>
                  <input
                    type="number"
                    className={styles.input}
                    value={formData.sortOrder}
                    onChange={(e) => handleFormChange('sortOrder', parseInt(e.target.value) || 0)}
                    min={0}
                    max={9999}
                  />
                </div>
                <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                  <label className={styles.label}>Mô tả</label>
                  <textarea
                    className={styles.textarea}
                    value={formData.description}
                    onChange={(e) => handleFormChange('description', e.target.value)}
                    placeholder="Mô tả ngắn về phòng ban..."
                    rows={3}
                    maxLength={500}
                  />
                  <span className={styles.charCount}>
                    {formData.description.length}/500
                  </span>
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.checkboxRow}>
                    <input
                      type="checkbox"
                      checked={formData.isActive}
                      onChange={(e) => handleFormChange('isActive', e.target.checked)}
                    />
                    <span>Phòng ban đang hoạt động</span>
                  </label>
                </div>
          </div>
        </div>
      </Slideout>

      {/* ── Deactivate Confirm Slideout ── */}
      <Slideout
        isOpen={!!confirmId}
        onClose={() => { if (!deactivating) setConfirmId(null); }}
        title="Xác nhận vô hiệu hóa"
        width="420px"
        customFooter={
          <>
            <button
              className={styles.cancelBtn}
              onClick={() => setConfirmId(null)}
              disabled={deactivating}
            >
              Hủy
            </button>
            <button
              className={styles.deactivateConfirmBtn}
              onClick={handleDeactivate}
              disabled={deactivating}
            >
              {deactivating
                ? <><i className="fas fa-spinner fa-spin"></i> Đang xử lý...</>
                : <><i className="fas fa-ban"></i> Vô hiệu hóa</>
              }
            </button>
          </>
        }
      >
        <div style={{ textAlign: 'center', padding: '1rem 0' }}>
          <div className={styles.confirmIcon}>
            <i className="fas fa-ban"></i>
          </div>
          <h3 className={styles.confirmTitle}>Vô hiệu hóa phòng ban?</h3>
          <p className={styles.confirmText}>
            Phòng ban này sẽ bị ẩn khỏi các biểu mẫu phân công. Dữ liệu hiện tại không bị xóa.
          </p>
        </div>
      </Slideout>
    </div>
  );
};

export default DepartmentsManagementPage;
