import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { Select } from '../../../../components/common';
import { useResponsive } from '../../../../hooks/useResponsive';
import { useFormOptions } from '../../../../hooks/useFormOptions';
import styles from './UsersFilters.module.css';

export interface UsersFilterValues {
  search:          string;
  role:            string;
  includeInactive: boolean;
}

interface UsersFiltersProps {
  filters:  UsersFilterValues;
  onChange: (f: UsersFilterValues) => void;
}

export const UsersFilters: React.FC<UsersFiltersProps> = ({ filters, onChange }) => {
  const { isMobile } = useResponsive();
  const { accountRoleOptions } = useFormOptions('accounts-list');
  const roleOptions = useMemo(
    () => [{ value: '', label: 'Tất cả vai trò' }, ...accountRoleOptions],
    [accountRoleOptions],
  );
  const [isExpanded, setIsExpanded] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const [dropdownStyle, setDropdownStyle] = useState<React.CSSProperties>({});

  const activeFilterCount = useMemo(() => {
    let count = 0;
    if (filters.role)             count++;
    if (filters.includeInactive)  count++;
    return count;
  }, [filters]);

  const hasActiveFilters = activeFilterCount > 0;

  const handleClear = () => {
    onChange({ ...filters, role: '', includeInactive: false });
    setIsExpanded(false);
  };

  const computeDropdownStyle = useCallback(() => {
    if (!buttonRef.current) return;
    const rect = buttonRef.current.getBoundingClientRect();
    const panelWidth = Math.min(300, window.innerWidth - 16);
    const centeredLeft = Math.max(8, (window.innerWidth - panelWidth) / 2);
    setDropdownStyle({ top: rect.bottom + 8, left: centeredLeft, width: panelWidth });
  }, []);

  const handleToggle = () => {
    if (!isExpanded) computeDropdownStyle();
    setIsExpanded((v) => !v);
  };

  useEffect(() => {
    if (!isExpanded) return;
    const close = () => setIsExpanded(false);
    window.addEventListener('scroll', close, { passive: true, capture: true });
    window.addEventListener('resize', close,  { passive: true });
    return () => {
      window.removeEventListener('scroll', close, { capture: true });
      window.removeEventListener('resize', close);
    };
  }, [isExpanded]);

  // ─── Mobile ──────────────────────────────────────────────────────────────
  if (isMobile) {
    return (
      <>
        {isExpanded && <div className={styles.filterBackdrop} onClick={() => setIsExpanded(false)} />}
        <div className={styles.container}>
          <div className={styles.mobileHeader}>
            <div className={styles.title}>Người dùng</div>
            <div className={styles.filterDropdownWrapper}>
              <button
                ref={buttonRef}
                className={styles.filterToggle}
                onClick={handleToggle}
                aria-expanded={isExpanded}
                type="button"
              >
                <i className="fas fa-filter" />
                <span>Lọc</span>
                {activeFilterCount > 0 && (
                  <span className={styles.filterBadge}>{activeFilterCount}</span>
                )}
                <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'}`} />
              </button>
              {isExpanded && (
                <div className={styles.mobileFilters} style={dropdownStyle}>
                  <Select
                    value={filters.role}
                    onChange={(e) => onChange({ ...filters, role: e.target.value })}
                    options={roleOptions}
                    size="small"
                    fullWidth
                  />
                  <label className={styles.checkboxLabel}>
                    <input
                      type="checkbox"
                      checked={filters.includeInactive}
                      onChange={(e) => onChange({ ...filters, includeInactive: e.target.checked })}
                    />
                    <span>Bao gồm không hoạt động</span>
                  </label>
                  {hasActiveFilters && (
                    <button className={styles.clearFiltersButton} onClick={handleClear} type="button">
                      <i className="fas fa-times-circle" />
                      <span>Xóa bộ lọc</span>
                    </button>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </>
    );
  }

  // ─── Desktop ──────────────────────────────────────────────────────────────
  return (
    <div className={styles.container}>
      <div className={styles.title}>Người dùng</div>
      <div className={styles.filters}>
        <div className={styles.searchWrapper}>
          <i className={`fas fa-search ${styles.searchIcon}`} />
          <input
            type="text"
            className={styles.searchInput}
            placeholder="Tìm theo tên, email..."
            value={filters.search}
            onChange={(e) => onChange({ ...filters, search: e.target.value })}
          />
        </div>
        <Select
          value={filters.role}
          onChange={(e) => onChange({ ...filters, role: e.target.value })}
          options={roleOptions}
          size="small"
        />
        <label className={styles.checkboxLabel}>
          <input
            type="checkbox"
            checked={filters.includeInactive}
            onChange={(e) => onChange({ ...filters, includeInactive: e.target.checked })}
          />
          <span>Không hoạt động</span>
        </label>
        {hasActiveFilters && (
          <button className={styles.clearFiltersButtonDesktop} onClick={handleClear} type="button">
            <i className="fas fa-times-circle" />
            <span>Xóa bộ lọc</span>
          </button>
        )}
      </div>
    </div>
  );
};
