import React, { useRef, useState, useEffect, useCallback } from 'react';
import styles from './DepartmentsFilters.module.css';

export interface DepartmentsFilterValues {
  search:          string;
  includeInactive: boolean;
}

interface Props {
  filters:  DepartmentsFilterValues;
  onChange: (filters: DepartmentsFilterValues) => void;
}

const DepartmentsFilters: React.FC<Props> = ({ filters, onChange }) => {
  const [mobileOpen, setMobileOpen]   = useState(false);
  const [dropdownStyle, setDropdownStyle] = useState<React.CSSProperties>({});
  const toggleBtnRef = useRef<HTMLButtonElement>(null);

  const activeCount = [filters.includeInactive].filter(Boolean).length;

  const computeDropdownStyle = useCallback(() => {
    if (!toggleBtnRef.current) return;
    const rect = toggleBtnRef.current.getBoundingClientRect();
    setDropdownStyle({
      position: 'fixed',
      top:      rect.bottom + 6,
      left:     Math.max(8, rect.left),
      right:    8,
      zIndex:   1050,
    });
  }, []);

  const handleToggleMobile = () => {
    if (!mobileOpen) computeDropdownStyle();
    setMobileOpen((prev) => !prev);
  };

  // Close panel on scroll / resize
  useEffect(() => {
    if (!mobileOpen) return;
    const close = () => setMobileOpen(false);
    window.addEventListener('scroll', close, { passive: true });
    window.addEventListener('resize', close);
    return () => {
      window.removeEventListener('scroll', close);
      window.removeEventListener('resize', close);
    };
  }, [mobileOpen]);

  const handleClear = () =>
    onChange({ search: '', includeInactive: false });

  const hasActiveFilters = filters.includeInactive;

  return (
    <div className={styles.filtersBar}>
      <span className={styles.filtersTitle}>
        <i className="fas fa-filter" />
        Bộ lọc
      </span>

      {/* Desktop */}
      <div className={styles.desktopFilters}>
        <div className={styles.searchWrapper}>
          <i className="fas fa-search" />
          <input
            type="text"
            className={styles.searchInput}
            placeholder="Tìm theo tên hoặc mã..."
            value={filters.search}
            onChange={(e) => onChange({ ...filters, search: e.target.value })}
          />
        </div>
        <label className={styles.checkboxLabel}>
          <input
            type="checkbox"
            checked={filters.includeInactive}
            onChange={(e) => onChange({ ...filters, includeInactive: e.target.checked })}
          />
          Bao gồm không hoạt động
        </label>
        {hasActiveFilters && (
          <button className={styles.clearBtn} onClick={handleClear}>
            <i className="fas fa-times" /> Xóa lọc
          </button>
        )}
      </div>

      {/* Mobile */}
      <div className={styles.mobileFilters}>
        <div className={styles.mobileRow}>
          <div className={styles.searchWrapper}>
            <i className="fas fa-search" />
            <input
              type="text"
              className={styles.searchInput}
              placeholder="Tìm kiếm..."
              value={filters.search}
              onChange={(e) => onChange({ ...filters, search: e.target.value })}
            />
          </div>
          <button
            ref={toggleBtnRef}
            className={`${styles.mobileToggleBtn} ${activeCount > 0 ? styles.hasFilters : ''}`}
            onClick={handleToggleMobile}
          >
            <i className="fas fa-sliders-h" />
            {activeCount > 0 && (
              <span className={styles.filterBadge}>{activeCount}</span>
            )}
          </button>
        </div>

        {mobileOpen && (
          <>
            <div className={styles.backdrop} onClick={() => setMobileOpen(false)} />
            <div className={styles.mobilePanel} style={dropdownStyle}>
              <div className={styles.mobilePanelHeader}>
                <span>Bộ lọc</span>
                <button className={styles.closeBtn} onClick={() => setMobileOpen(false)}>
                  <i className="fas fa-times" />
                </button>
              </div>
              <div className={styles.mobilePanelBody}>
                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={filters.includeInactive}
                    onChange={(e) => onChange({ ...filters, includeInactive: e.target.checked })}
                  />
                  Bao gồm không hoạt động
                </label>
              </div>
              {hasActiveFilters && (
                <div className={styles.mobilePanelFooter}>
                  <button className={styles.clearBtn} onClick={() => { handleClear(); setMobileOpen(false); }}>
                    <i className="fas fa-times" /> Xóa tất cả bộ lọc
                  </button>
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default DepartmentsFilters;
