/**
 * UsersManagementPage
 * Admin page for listing, adding, editing and deactivating users.
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { userService, CreateUserRequest, UpdateUserRequest } from '../../services/user';
import type { BffUserStatsDto } from '../../services/user/responseModel';
import { departmentService } from '../../services/department';
import { User } from '../../models/User';
import { Department } from '../../models/Department';
import { Slideout } from '../../components/common/Slideout';
import { TableCard, Pagination, Button } from '../../components/common';
import { useResponsive } from '../../hooks/useResponsive';
import { useAppToast } from '../../hooks/useAppToast';
import { useMinLoadingTime } from '../../hooks/useMinLoadingTime';
import { useFormOptions } from '../../hooks/useFormOptions';
import { UsersStatsCards } from './components/UsersStatsCards';
import { UsersFilters } from './components/UsersFilters';
import type { UsersFilterValues } from './components/UsersFilters';
import { UsersListSkeleton } from './components/UsersListSkeleton';
import styles from './UsersManagementPage.module.css';

// ─────────────────────────────────────────────────────────────────────────────
// Form modal state
// ─────────────────────────────────────────────────────────────────────────────

interface UserFormData {
  fullName:      string;
  email:         string;
  firstName:     string;
  lastName:      string;
  role:          string;
  departmentId:  string;
  skills:        string;
  isActive:      boolean;
  password:      string;
}

const emptyForm: UserFormData = {
  fullName:     '',
  email:        '',
  firstName:    '',
  lastName:     '',
  role:         'staff',
  departmentId: '',
  skills:       '',
  isActive:     true,
  password:     '',
};

const PAGE_SIZE = 20;
// ─────────────────────────────────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────────────────────────────────

const UsersManagementPage: React.FC = () => {
  const { isMobile, isTablet } = useResponsive();
  const toast = useAppToast();
  const slideoutWidth = isMobile ? '100%' : isTablet ? '480px' : '600px';
  const { accountRoleOptions } = useFormOptions('accounts-list');

  const getRoleLabel = (role?: string) => {
    const normalized = role?.toLowerCase() ?? '';
    return accountRoleOptions.find((o) => o.value === normalized)?.label ?? role ?? '—';
  };

  const [users, setUsers]               = useState<User[]>([]);
  const [departments, setDepartments]   = useState<Department[]>([]);
  const [totalCount, setTotalCount]     = useState(0);
  const [currentPage, setCurrentPage]   = useState(1);
  const [loading, setLoading]           = useState(true);
  const showLoading                     = useMinLoadingTime(loading);
  const [stats, setStats]               = useState<BffUserStatsDto>({ total: 0, active: 0, inactive: 0, admin: 0, manager: 0, staff: 0 });
  const [statsLoading, setStatsLoading] = useState(true);

  const [filters, setFilters] = useState<UsersFilterValues>({
    search: '', role: '', includeInactive: false,
  });

  const totalPages = Math.ceil(totalCount / PAGE_SIZE);

  // Modal
  const [modalOpen, setModalOpen]       = useState(false);
  const [editingUser, setEditingUser]   = useState<User | null>(null);
  const [formData, setFormData]         = useState<UserFormData>(emptyForm);
  const [formError, setFormError]       = useState<string | null>(null);
  const [saving, setSaving]             = useState(false);

  // Deactivate confirm
  const [confirmId, setConfirmId]       = useState<string | null>(null);
  const [deactivating, setDeactivating] = useState(false);

  // ── Load ─────────────────────────────────────────────────────────────────
  const loadCancelRef      = useRef(false);
  const loadStatsCancelRef = useRef(false);

  const loadUsers = useCallback(async () => {
    loadCancelRef.current = false;
    setLoading(true);
    try {
      const [pagedResult, deptsData] = await Promise.all([
        userService.getUsers({
          search: filters.search || undefined,
          role: filters.role || undefined,
          includeInactive: filters.includeInactive,
          page: currentPage,
          pageSize: PAGE_SIZE,
        }),
        departmentService.getDepartments({ includeInactive: false }),
      ]);
      if (loadCancelRef.current) return;
      setUsers(pagedResult.items);
      setTotalCount(pagedResult.totalCount);
      setDepartments(deptsData.items);
    } catch (err: unknown) {
      if (!loadCancelRef.current) toast.fromError(err, 'Không thể tải danh sách người dùng, vui lòng thử lại');
    } finally {
      if (!loadCancelRef.current) setLoading(false);
    }
  }, [filters.search, filters.role, filters.includeInactive, currentPage]);

  const loadStats = useCallback(async () => {
    loadStatsCancelRef.current = false;
    setStatsLoading(true);
    try {
      const data = await userService.getStats();
      if (loadStatsCancelRef.current) return;
      setStats(data);
    } catch {
      // stats errors are non-critical; page remains usable
    } finally {
      if (!loadStatsCancelRef.current) setStatsLoading(false);
    }
  }, []);

  useEffect(() => { const t = setTimeout(loadUsers, 0); return () => { clearTimeout(t); loadCancelRef.current = true; }; }, [loadUsers]);
  useEffect(() => { const t = setTimeout(loadStats, 0); return () => { clearTimeout(t); loadStatsCancelRef.current = true; }; }, [loadStats]);

  // ── Modal helpers ─────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditingUser(null);
    setFormData(emptyForm);
    setFormError(null);
    setModalOpen(true);
  };

  const openEdit = (user: User) => {
    setEditingUser(user);
    setFormData({
      fullName:     user.fullName,
      email:        user.email,
      firstName:    user.firstName,
      lastName:     user.lastName,
      role:         user.role?.toLowerCase?.() ?? 'staff',
      departmentId: user.departmentId ?? '',
      skills:       user.skills.join(', '),
      isActive:     user.isActive,
      password:     '',
    });
    setFormError(null);
    setModalOpen(true);
  };

  const closeModal = () => {
    if (saving) return;
    setModalOpen(false);
    setEditingUser(null);
    setFormData(emptyForm);
    setFormError(null);
  };

  const handleFormChange = (field: keyof UserFormData, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setFormError(null);
  };

  const handleSave = async () => {
    if (!formData.fullName.trim()) { setFormError('Họ tên không được để trống'); return; }

    // Sync department name from departments list
    const dept = departments.find((d) => d.id === formData.departmentId);

    setSaving(true);
    setFormError(null);
    try {
      if (editingUser) {
        const req: UpdateUserRequest = {
          fullName:       formData.fullName.trim(),
          email:          formData.email?.trim() || undefined,
          lastName:       formData.lastName.trim()  || undefined,
          role:           formData.role,
          departmentId:   formData.departmentId || undefined,
          departmentName: dept?.name,
          skills:         formData.skills.trim() || undefined,
          isActive:       formData.isActive,
        };
        await userService.updateUser(editingUser.id, req);
      } else {
        const req: CreateUserRequest = {
          fullName:       formData.fullName.trim(),
          email:          formData.email.trim() || undefined,
          firstName:      formData.firstName.trim() || undefined,
          lastName:       formData.lastName.trim()  || undefined,
          role:           formData.role,
          departmentId:   formData.departmentId || undefined,
          departmentName: dept?.name,
          skills:         formData.skills.trim() || undefined,
          isActive:       formData.isActive,
          password:       formData.password.trim() || undefined,
        };
        await userService.createUser(req);
      }
      await loadUsers();
      await loadStats();
      toast.success(editingUser ? 'Cập nhật người dùng thành công' : 'Tạo người dùng thành công');
      closeModal();
    } catch (err: any) {
      const message = err?.message ?? 'Đã có lỗi xảy ra. Vui lòng thử lại.';
      setFormError(message);
      toast.fromError(err, 'Đã có lỗi xảy ra. Vui lòng thử lại.');
    } finally {
      setSaving(false);
    }
  };

  // ── Deactivate ────────────────────────────────────────────────────────────

  const handleDeactivate = async () => {
    if (!confirmId) return;
    setDeactivating(true);
    try {
      await userService.deactivateUser(confirmId);
      await loadUsers();
      await loadStats();
      toast.success('Vô hiệu hóa người dùng thành công');
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể vô hiệu hóa người dùng, vui lòng thử lại');
    } finally {
      setDeactivating(false);
      setConfirmId(null);
    }
  };

  // ── Render ────────────────────────────────────────────────────────────────

  const handleFilterChange = (newFilters: UsersFilterValues) => {
    setFilters(newFilters);
    setCurrentPage(1);
  };

  return (
    <div className={styles.page}>
      {/* 1. Page Header */}
      <div className={styles.header}>
        <h1 className={styles.title}>
          <i className="fas fa-users" />
          Quản lý người dùng
        </h1>
        <Button variant="primary" onClick={openCreate}>
          <i className="fas fa-plus" />
          {!isMobile && ' Thêm người dùng'}
        </Button>
      </div>

      {/* 2. Stats Cards */}
      <UsersStatsCards stats={stats} loading={showLoading || statsLoading} />

      {/* 3. TableCard: Filters + Table */}
      <TableCard
        header={<UsersFilters filters={filters} onChange={handleFilterChange} />}
        footer={
          !showLoading && users.length > 0 ? (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          ) : undefined
        }
      >
        {showLoading && <UsersListSkeleton />}

        {!showLoading && users.length === 0 && (
          <div className={styles.emptyState}>
            <i className="fas fa-user-slash" />
            <p>Không tìm thấy người dùng nào</p>
          </div>
        )}

        {!showLoading && users.length > 0 && (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Họ tên</th>
                  <th>Email</th>
                  <th>Vai trò</th>
                  <th>Phòng ban</th>
                  <th>Trạng thái</th>
                  <th className={styles.actionsCol}>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {users.map((user) => (
                  <tr key={user.id} className={!user.isActive ? styles.inactiveRow : ''}>
                    <td>
                      <div className={styles.userCell}>
                        <div className={styles.avatar}>
                          {user.avatar
                            ? <img src={user.avatar} alt={user.fullName} />
                            : <span>{user.fullName.charAt(0).toUpperCase()}</span>
                          }
                        </div>
                        <div>
                          <div className={styles.userName}>{user.fullName}</div>
                          <div className={styles.userUsername}>@{user.username}</div>
                        </div>
                      </div>
                    </td>
                    <td className={styles.emailCell}>
                      {user.email || <span className={styles.na}>—</span>}
                    </td>
                    <td>
                      <span className={`${styles.roleBadge} ${styles[`role_${user.role}`]}`}>
                        {getRoleLabel(user.role)}
                      </span>
                    </td>
                    <td>{user.departmentName || <span className={styles.na}>—</span>}</td>
                    <td>
                      <span className={`${styles.statusBadge} ${user.isActive ? styles.active : styles.inactive}`}>
                        {user.isActive ? 'Hoạt động' : 'Ngừng hoạt động'}
                      </span>
                    </td>
                    <td className={styles.actionsCell}>
                      <button
                        className={styles.editBtn}
                        onClick={() => openEdit(user)}
                        title="Chỉnh sửa"
                      >
                        <i className="fas fa-pen"></i>
                      </button>
                      {user.isActive && (
                        <button
                          className={styles.deactivateBtn}
                          onClick={() => setConfirmId(user.id)}
                          title="Vô hiệu hóa"
                        >
                          <i className="fas fa-ban"></i>
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </TableCard>

      {/* ── Add / Edit Slideout ── */}
      <Slideout
        isOpen={modalOpen}
        onClose={closeModal}
        title={
          <span style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <i className={editingUser ? 'fas fa-user-edit' : 'fas fa-user-plus'} style={{ color: 'var(--primary-color)' }} />
            {editingUser ? 'Chỉnh sửa người dùng' : 'Thêm người dùng mới'}
          </span>
        }
        width={slideoutWidth}
        customFooter={
          <>
            <button className={styles.cancelBtn} onClick={closeModal} disabled={saving}>
              Hủy
            </button>
            <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
              {saving
                ? <><i className="fas fa-spinner fa-spin"></i> Đang lưu...</>
                : <><i className="fas fa-save"></i> {editingUser ? 'Cập nhật' : 'Tạo mới'}</>
              }
            </button>
          </>
        }
      >
        <div className={styles.form}>
          {formError && (
            <div className={styles.formError}>
              <i className="fas fa-exclamation-circle"></i>
              {formError}
            </div>
          )}

          <div className={styles.formGrid}>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Họ tên <span className={styles.required}>*</span></label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.fullName}
                    onChange={(e) => handleFormChange('fullName', e.target.value)}
                    placeholder="Nguyễn Văn A"
                    required
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Email <span className={styles.hint}>(không bắt buộc)</span></label>
                  <input
                    type="email"
                    className={styles.input}
                    value={formData.email}
                    onChange={(e) => handleFormChange('email', e.target.value)}
                    placeholder="email@hospital.vn"
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Tên</label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.firstName}
                    onChange={(e) => handleFormChange('firstName', e.target.value)}
                    placeholder="Văn A"
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Họ</label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.lastName}
                    onChange={(e) => handleFormChange('lastName', e.target.value)}
                    placeholder="Nguyễn"
                  />
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Vai trò</label>
                  <select
                    className={styles.select}
                    value={formData.role}
                    onChange={(e) => handleFormChange('role', e.target.value)}
                  >
                    {accountRoleOptions.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                </div>
                <div className={styles.formGroup}>
                  <label className={styles.label}>Phòng ban</label>
                  <select
                    className={styles.select}
                    value={formData.departmentId}
                    onChange={(e) => handleFormChange('departmentId', e.target.value)}
                  >
                    <option value="">— Chọn phòng ban —</option>
                    {departments.map((d) => (
                      <option key={d.id} value={d.id}>{d.name}</option>
                    ))}
                  </select>
                </div>
                <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                  <label className={styles.label}>Kỹ năng <span className={styles.hint}>(phân cách bằng dấu phẩy)</span></label>
                  <input
                    type="text"
                    className={styles.input}
                    value={formData.skills}
                    onChange={(e) => handleFormChange('skills', e.target.value)}
                    placeholder="Điện, Nước, Điều hòa"
                  />
                </div>
                {!editingUser && (
                  <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                    <label className={styles.label}>Mật khẩu ban đầu</label>
                    <input
                      type="password"
                      className={styles.input}
                      value={formData.password}
                      onChange={(e) => handleFormChange('password', e.target.value)}
                      placeholder="Để trống sẽ dùng mật khẩu mặc định"
                      autoComplete="new-password"
                    />
                  </div>
                )}
                <div className={styles.formGroup}>
                  <label className={styles.checkboxRow}>
                    <input
                      type="checkbox"
                      checked={formData.isActive}
                      onChange={(e) => handleFormChange('isActive', e.target.checked)}
                    />
                    <span>Tài khoản đang hoạt động</span>
                  </label>
                </div>
          </div>
        </div>
      </Slideout>

      {/* ── Deactivate Confirm Slideout ── */}
      <Slideout
        isOpen={!!confirmId}
        onClose={() => { if (!deactivating) setConfirmId(null); }}
        title="Xác nhận vô hiệu hóa"
        width="420px"
        customFooter={
          <>
            <button
              className={styles.cancelBtn}
              onClick={() => setConfirmId(null)}
              disabled={deactivating}
            >
              Hủy
            </button>
            <button
              className={styles.deactivateConfirmBtn}
              onClick={handleDeactivate}
              disabled={deactivating}
            >
              {deactivating
                ? <><i className="fas fa-spinner fa-spin"></i> Đang xử lý...</>
                : <><i className="fas fa-ban"></i> Vô hiệu hóa</>
              }
            </button>
          </>
        }
      >
        <div style={{ textAlign: 'center', padding: '1rem 0' }}>
          <div className={styles.confirmIcon}>
            <i className="fas fa-ban"></i>
          </div>
          <h3 className={styles.confirmTitle}>Vô hiệu hóa tài khoản?</h3>
          <p className={styles.confirmText}>
            Người dùng này sẽ không thể đăng nhập cho đến khi được kích hoạt lại.
          </p>
        </div>
      </Slideout>
    </div>
  );
};

export default UsersManagementPage;
