/**
 * Redux slice for in-app notifications.
 *
 * State shape:
 *  - items:       visible notification list (most-recent first)
 *  - unreadCount: quick badge counter (kept separate for header polling)
 *  - loading:     true while the list is being fetched
 *  - loadingMore: true while load-more is in progress
 *  - page:        current page index
 *  - hasMore:     whether there are more pages to load
 *  - error:       last error string (null when clean)
 */
import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit';
import { notificationService } from '../../services/notifications/service';
import type { NotificationDto } from '../../services/notifications/types';

// ── State interface ──────────────────────────────────────────────────────────

interface NotificationState {
  items:       NotificationDto[];
  unreadCount: number;
  loading:     boolean;
  loadingMore: boolean;
  page:        number;
  hasMore:     boolean;
  error:       string | null;
}

const initialState: NotificationState = {
  items:       [],
  unreadCount: 0,
  loading:     false,
  loadingMore: false,
  page:        1,
  hasMore:     true,
  error:       null,
};

// ── Async thunks ──────────────────────────────────────────────────────────────

/** Fetch first page of notifications (replaces current list). */
export const fetchNotifications = createAsyncThunk(
  'notifications/fetchNotifications',
  async (unreadOnly: boolean = false) => {
    return await notificationService.getNotifications(unreadOnly, 1, 20);
  }
);

/** Fetch next page and append to existing list. */
export const fetchMoreNotifications = createAsyncThunk(
  'notifications/fetchMoreNotifications',
  async ({ unreadOnly, page }: { unreadOnly: boolean; page: number }) => {
    return await notificationService.getNotifications(unreadOnly, page, 20);
  }
);

/** Fetch unread count only (used for header badge polling). */
export const fetchUnreadCount = createAsyncThunk(
  'notifications/fetchUnreadCount',
  async () => {
    return await notificationService.getUnreadCount();
  }
);

/** Mark a single notification as read. */
export const markNotificationRead = createAsyncThunk(
  'notifications/markRead',
  async (id: string) => {
    await notificationService.markRead(id);
    return id;
  }
);

/** Mark all notifications as read. */
export const markAllNotificationsRead = createAsyncThunk(
  'notifications/markAllRead',
  async () => {
    await notificationService.markAllRead();
  }
);

/**
 * Mark all unread notifications for a given entityId (and optional types) as read.
 * Used when the chat / comments tab is opened so the badge clears automatically.
 * Fire-and-forget: optimistic update applied even if the API call fails.
 */
export const markEntityNotificationsRead = createAsyncThunk(
  'notifications/markReadByEntity',
  async ({ entityId, types }: { entityId: string; types?: string[] }) => {
    // Best-effort API call — we don't throw on failure so optimistic update still runs
    try {
      await notificationService.markReadByEntity(entityId, types);
    } catch {
      // Non-fatal: state is updated optimistically below regardless
    }
    return { entityId, types };
  }
);

/** Delete a single notification. */
export const deleteNotification = createAsyncThunk(
  'notifications/delete',
  async (id: string) => {
    await notificationService.deleteNotification(id);
    return id;
  }
);

// ── Slice ─────────────────────────────────────────────────────────────────────

const notificationSlice = createSlice({
  name: 'notifications',
  initialState,
  reducers: {
    /**
     * Push a real-time notification from SignalR to the top of the list.
     * Also increments the unread badge.
     */
    pushNotification(state, action: PayloadAction<NotificationDto>) {
      state.items.unshift(action.payload);
      if (!action.payload.isRead) {
        state.unreadCount += 1;
      }
    },

    /** Directly set the unread count (e.g. after a background poll). */
    setUnreadCount(state, action: PayloadAction<number>) {
      state.unreadCount = action.payload;
    },

    /** Clear all items (e.g. on logout). */
    clearNotifications(state) {
      state.items       = [];
      state.unreadCount = 0;
      state.page        = 1;
      state.hasMore     = true;
      state.error       = null;
    },
  },
  extraReducers: (builder) => {
    // ── fetchNotifications ────────────────────────────────────────────────
    builder
      .addCase(fetchNotifications.pending, (state) => {
        state.loading = true;
        state.error   = null;
      })
      .addCase(fetchNotifications.fulfilled, (state, action) => {
        state.loading     = false;
        state.items       = action.payload.items;
        state.unreadCount = action.payload.unreadCount;
        state.page        = 1;
        state.hasMore     = action.payload.items.length === action.payload.pageSize
          && action.payload.totalCount > action.payload.items.length;
      })
      .addCase(fetchNotifications.rejected, (state, action) => {
        state.loading = false;
        state.error   = action.error.message ?? 'Lỗi tải thông báo';
      });

    // ── fetchMoreNotifications ────────────────────────────────────────────
    builder
      .addCase(fetchMoreNotifications.pending, (state) => {
        state.loadingMore = true;
      })
      .addCase(fetchMoreNotifications.fulfilled, (state, action) => {
        state.loadingMore = false;
        state.items       = [...state.items, ...action.payload.items];
        state.page        = action.payload.page;
        state.hasMore     = state.items.length < action.payload.totalCount;
      })
      .addCase(fetchMoreNotifications.rejected, (state, action) => {
        state.loadingMore = false;
        state.error       = action.error.message ?? 'Lỗi tải thêm';
      });

    // ── fetchUnreadCount ──────────────────────────────────────────────────
    builder.addCase(fetchUnreadCount.fulfilled, (state, action) => {
      state.unreadCount = action.payload;
    });

    // ── markNotificationRead ──────────────────────────────────────────────
    builder.addCase(markNotificationRead.fulfilled, (state, action) => {
      const notif = state.items.find((n) => n.id === action.payload);
      if (notif && !notif.isRead) {
        notif.isRead     = true;
        notif.readAt     = new Date().toISOString();
        state.unreadCount = Math.max(0, state.unreadCount - 1);
      }
    });

    // ── markAllNotificationsRead ──────────────────────────────────────────
    builder.addCase(markAllNotificationsRead.fulfilled, (state) => {
      const now = new Date().toISOString();
      state.items.forEach((n) => {
        if (!n.isRead) { n.isRead = true; n.readAt = now; }
      });
      state.unreadCount = 0;
    });

    // ── markEntityNotificationsRead ───────────────────────────────────────
    builder.addCase(markEntityNotificationsRead.fulfilled, (state, action) => {
      const { entityId, types } = action.payload;
      const now = new Date().toISOString();
      let delta = 0;
      state.items.forEach((n) => {
        if (!n.isRead && n.entityId === entityId) {
          if (!types || types.includes(n.type)) {
            n.isRead  = true;
            n.readAt  = now;
            delta    += 1;
          }
        }
      });
      state.unreadCount = Math.max(0, state.unreadCount - delta);
    });

    // ── deleteNotification ────────────────────────────────────────────────
    builder.addCase(deleteNotification.fulfilled, (state, action) => {
      const idx = state.items.findIndex((n) => n.id === action.payload);
      if (idx !== -1) {
        if (!state.items[idx].isRead) {
          state.unreadCount = Math.max(0, state.unreadCount - 1);
        }
        state.items.splice(idx, 1);
      }
    });
  },
});

export const {
  pushNotification,
  setUnreadCount,
  clearNotifications,
} = notificationSlice.actions;

export default notificationSlice.reducer;
