import React from 'react';
import styles from './StatsCard.module.css';

export interface StatsCardProps {
  label: string;
  value: number | string;
  icon?: string;
  variant?: 'total' | 'primary' | 'info' | 'warning' | 'success' | 'danger' | 'gray';
  loading?: boolean;
  onClick?: () => void;
  active?: boolean;
}

export const StatsCard: React.FC<StatsCardProps> = ({
  label,
  value,
  icon,
  variant = 'total',
  loading = false,
  onClick,
  active = false,
}) => {
  if (loading) {
    return (
      <div className={`${styles.card} ${styles.skeleton}`}>
        <div className={styles.skeletonLabel} />
        <div className={styles.skeletonValue} />
      </div>
    );
  }

  const classNames = [
    styles.card,
    onClick ? styles.clickable : '',
    active  ? styles.active   : '',
  ].filter(Boolean).join(' ');

  return (
    <div className={classNames} onClick={onClick} role={onClick ? 'button' : undefined} tabIndex={onClick ? 0 : undefined}>
      <div className={styles.label}>{label}</div>
      {icon ? (
        <div className={styles.valueRow}>
          <div className={`${styles.value} ${styles[variant]}`}>{value}</div>
          <i className={`${icon} ${styles.icon} ${styles[variant]}`}></i>
        </div>
      ) : (
        <div className={`${styles.value} ${styles[variant]}`}>{value}</div>
      )}
    </div>
  );
};
