import React, { useState, useRef, useEffect } from 'react';
import styles from './AppSwitcher.module.css';

export type AppId = 'task-management' | 'medical-incidents';

export interface AppDef {
  id: AppId;
  name: string;
  shortName: string;
  icon: string;
  description: string;
  homeRoute: string;
  accentColor: string;
}

export const APPS: AppDef[] = [
  {
    id: 'task-management',
    name: 'QLCV & SC Y Khoa',
    shortName: 'QLCV',
    icon: 'fas fa-tasks',
    description: 'Quản lý công việc & phiếu yêu cầu',
    homeRoute: '/tickets',
    accentColor: '#3B82F6',
  },
  {
    id: 'medical-incidents',
    name: 'QL Sự Cố Y Khoa',
    shortName: 'Sự Cố',
    icon: 'fas fa-hospital-user',
    description: 'Quản lý và theo dõi sự cố y khoa',
    homeRoute: '/medical-incidents',
    accentColor: '#EF4444',
  },
];

export interface AppSwitcherProps {
  activeApp: AppId;
  onSwitch: (app: AppDef) => void;
}

export const AppSwitcher: React.FC<AppSwitcherProps> = ({ activeApp, onSwitch }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const current = APPS.find((a) => a.id === activeApp) ?? APPS[0];

  // Close on click outside
  useEffect(() => {
    if (!isOpen) return;
    const handleClick = (e: MouseEvent | TouchEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClick);
    document.addEventListener('touchstart', handleClick);
    return () => {
      document.removeEventListener('mousedown', handleClick);
      document.removeEventListener('touchstart', handleClick);
    };
  }, [isOpen]);

  // Close on Escape
  useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setIsOpen(false);
    };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [isOpen]);

  return (
    <div ref={containerRef} className={styles.wrapper}>
      {/* Trigger button */}
      <button
        className={`${styles.trigger} ${isOpen ? styles.triggerOpen : ''}`}
        onClick={() => setIsOpen((v) => !v)}
        aria-haspopup="true"
        aria-expanded={isOpen}
        aria-label="Chọn ứng dụng"
        title="Chuyển đổi ứng dụng"
      >
        <span
          className={styles.triggerIcon}
          style={{ '--app-color': current.accentColor } as React.CSSProperties}
        >
          <i className={current.icon} />
        </span>
        <span className={styles.triggerName}>{current.name}</span>
        <i className={`fas fa-chevron-down ${styles.chevron} ${isOpen ? styles.chevronOpen : ''}`} />
      </button>

      {/* Dropdown */}
      {isOpen && (
        <div className={styles.dropdown} role="menu">
          <div className={styles.dropdownHeader}>
            <i className="fas fa-th-large" />
            <span>Chọn ứng dụng</span>
          </div>
          <div className={styles.appGrid}>
            {APPS.map((app) => {
              const isActive = app.id === activeApp;
              return (
                <button
                  key={app.id}
                  className={`${styles.appCard} ${isActive ? styles.appCardActive : ''}`}
                  onClick={() => {
                    onSwitch(app);
                    setIsOpen(false);
                  }}
                  role="menuitem"
                  aria-current={isActive ? 'true' : undefined}
                  style={{ '--app-color': app.accentColor } as React.CSSProperties}
                >
                  <span className={styles.appCardIcon}>
                    <i className={app.icon} />
                  </span>
                  <div className={styles.appCardInfo}>
                    <span className={styles.appCardName}>{app.name}</span>
                    <span className={styles.appCardDesc}>{app.description}</span>
                  </div>
                  {isActive && (
                    <i className={`fas fa-check-circle ${styles.appCardCheck}`} />
                  )}
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};
