import React, { useState, useRef, useEffect } from 'react';
import styles from './Sidebar.module.css';
import { Avatar } from '../../common/Avatar';
// import { Badge } from '../../common/Badge';
// import { Tooltip } from '../../common/Tooltip';

export interface NavItem {
  id: string;
  label: string;
  icon: string;
  path: string;
  badge?: number;
}

export interface NavSection {
  title: string;
  items: NavItem[];
}

export interface SidebarProps {
  sections: NavSection[];
  activePath: string;
  userName: string;
  userRole: string;
  userInitials: string;
  onNavigate: (path: string) => void;
  onLogout: () => void;
  /** When true, shows a spinner on the logout button and disables it */
  logoutLoading?: boolean;
  isCollapsed?: boolean;
  onToggleCollapse?: () => void;
  isMobile?: boolean;
  isSmallDesktop?: boolean;
  isOpen?: boolean;
  /** Icon class for the logo area (e.g. 'fas fa-tasks'). Defaults to 'fas fa-hospital-user'. */
  logoIcon?: string;
  /** Text label for the logo area. Defaults to 'QLCV & SC Y Khoa'. */
  logoLabel?: string;
}

export const Sidebar: React.FC<SidebarProps> = ({
  sections,
  activePath,
  userName,
  userRole,
  userInitials,
  onNavigate,
  onLogout,
  logoutLoading = false,
  isCollapsed = false,
  onToggleCollapse,
  isMobile = false,
  isSmallDesktop = false,
  isOpen = false,
  logoIcon = 'fas fa-hospital-user',
  logoLabel = 'QLCV & SC Y Khoa',
}) => {
  // For touch devices on small desktop: temporary expansion on click
  const [isTemporarilyExpanded, setIsTemporarilyExpanded] = useState(false);
  const sidebarRef = useRef<HTMLElement>(null);

  // Handle click outside to collapse on small desktop with touch
  useEffect(() => {
    if (!isSmallDesktop || !isTemporarilyExpanded) return;

    const handleClickOutside = (event: MouseEvent | TouchEvent) => {
      if (sidebarRef.current && !sidebarRef.current.contains(event.target as Node)) {
        setIsTemporarilyExpanded(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('touchstart', handleClickOutside);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('touchstart', handleClickOutside);
    };
  }, [isSmallDesktop, isTemporarilyExpanded]);

  // Handle sidebar click to expand on touch devices (small desktop)
  const handleSidebarClick = () => {
    if (isSmallDesktop && isCollapsed && !isTemporarilyExpanded) {
      setIsTemporarilyExpanded(true);
    }
  };

  // Determine if content should be shown (not collapsed or temporarily expanded)
  const showContent = !isCollapsed || isTemporarilyExpanded;

  return (
    <aside 
      ref={sidebarRef}
      className={`${styles.sidebar} ${isCollapsed ? styles.collapsed : ''} ${isSmallDesktop ? styles.smallDesktop : ''} ${isTemporarilyExpanded ? styles.tempExpanded : ''} ${isOpen ? styles.open : ''}`}
      aria-label="Điều hướng chính"
      aria-expanded={showContent}
      onClick={handleSidebarClick}
    >
      {/* Toggle button - only show on desktop large, not on small desktop */}
      {!isMobile && !isSmallDesktop && onToggleCollapse && (
        <button 
          className={styles.toggleButton}
          onClick={onToggleCollapse}
          aria-label={isCollapsed ? "Mở rộng menu" : "Thu gọn menu"}
          title={isCollapsed ? "Mở rộng menu" : "Thu gọn menu"}
        >
          <i className={isCollapsed ? "fas fa-bars" : "fas fa-times"}></i>
        </button>
      )}

      <div className={styles.header}>
        <div className={styles.logo}>
          <i className={logoIcon}></i>
          <span className={styles.logoText}>{logoLabel}</span>
        </div>
      </div>

      <nav className={styles.nav}>
        {sections.map((section, idx) => (
          <div key={idx} className={styles.section}>
            <div className={styles.sectionTitle}>{section.title}</div>
            {section.items.map((item) => (
              <button
                  key={item.id}
                  className={`${styles.navItem} ${
                    activePath === item.path ? styles.active : ''
                  }`}
                  onClick={(e) => {
                    e.stopPropagation();
                    onNavigate(item.path);
                    if (isTemporarilyExpanded) {
                      setIsTemporarilyExpanded(false);
                    }
                  }}
                  aria-label={item.label}
                >
                  <i className={item.icon}></i>
                  <span className={styles.navItemText}>{item.label}</span>
                  {/* {item.badge !== undefined && item.badge > 0 && (
                    <>
                      <Badge variant="danger" size="sm" rounded className={styles.navItemBadge}>
                        {item.badge}
                      </Badge>
                      <span className={styles.badgeDot}></span>
                    </>
                  )} */}
                </button>
            ))}
          </div>
        ))}
      </nav>

      <div className={styles.footer}>
        <div className={styles.userProfile}>
          <Avatar initials={userInitials} size="md" />
          <div className={styles.userInfo}>
            <div className={styles.userName}>{userName}</div>
            <div className={styles.userRole}>{userRole}</div>
          </div>
          <button
            className={styles.logoutButton}
            onClick={(e) => {
              e.stopPropagation();
              if (!logoutLoading) onLogout();
            }}
            disabled={logoutLoading}
            aria-label={logoutLoading ? 'Đang đăng xuất…' : 'Đăng xuất'}
            title={logoutLoading ? 'Đang đăng xuất…' : 'Đăng xuất'}
          >
            {logoutLoading
              ? <i className="fas fa-spinner fa-spin"></i>
              : <i className="fas fa-sign-out-alt"></i>
            }
          </button>
        </div>
      </div>
    </aside>
  );
};
