/**
 * useFormOptions — fetches ALL form init-data from the BFF and returns
 * typed SelectOption arrays for every dropdown / chip-filter in the UI.
 *
 * A single API call is made per mount; all option lists are derived from it.
 *
 * Usage:
 *   const {
 *     loading,
 *     departmentOptions,
 *     ticketPriorityOptions,
 *     taskPriorityOptions,
 *     alertSeverityOptions,
 *     ...
 *   } = useFormOptions('create-ticket');
 */

import { useState, useEffect } from 'react';
import { formInitService, FormInitData } from '../services/formInit';
import type { SelectOption } from '../components/common/Select/Select';

const EMPTY: SelectOption[] = [];

const toOpts = (items: { value: string; label: string }[] = []): SelectOption[] =>
  items.map((o) => ({ value: o.value, label: o.label }));

interface UseFormOptionsResult {
  loading: boolean;
  /** The user's own department ID from the JWT — use as the initial value for department selects. */
  defaultDepartmentId:       string | undefined;
  departmentOptions:         SelectOption[];
  ticketPriorityOptions:     SelectOption[];
  ticketCategoryOptions:     SelectOption[];
  ticketTypeOptions:         SelectOption[];
  ticketStatusOptions:       SelectOption[];
  taskPriorityOptions:       SelectOption[];
  taskStatusOptions:         SelectOption[];
  assignmentStrategyOptions: SelectOption[];
  taskSkillOptions:          SelectOption[];
  alertSeverityOptions:      SelectOption[];
  alertTypeOptions:          SelectOption[];
  deadlineFilterOptions:     SelectOption[];
  taskSortOrderOptions:      SelectOption[];
  incidentStatusOptions:         SelectOption[];
  incidentSeverityOptions:        SelectOption[];
  incidentReportTypeOptions:      SelectOption[];
  incidentCategoryOptions:        SelectOption[];
  patientGenderOptions:           SelectOption[];
  incidentOccurrenceStatusOptions: SelectOption[];
  incidentNotifyStatusOptions:    SelectOption[];
  accountRoleOptions:             SelectOption[];
  accountStatusOptions:           SelectOption[];
  accountGenderOptions:           SelectOption[];
}

export const useFormOptions = (formName = 'default'): UseFormOptionsResult => {
  const [data, setData] = useState<FormInitData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      if (cancelled) return;
      formInitService
        .getInitData(formName)
        .then((d) => { if (!cancelled) setData(d); })
        .catch(() => { /* Silently fail — forms remain usable with empty dropdowns. */ })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [formName]);

  return {
    loading,
    defaultDepartmentId:       data?.defaultDepartmentId,
    departmentOptions:         data ? data.departments.map((d) => ({ value: d.id, label: d.name })) : EMPTY,
    ticketPriorityOptions:     toOpts(data?.ticketPriorities),
    ticketCategoryOptions:     toOpts(data?.ticketCategories),
    ticketTypeOptions:         toOpts(data?.ticketTypes),
    ticketStatusOptions:       toOpts(data?.ticketStatuses),
    taskPriorityOptions:       toOpts(data?.taskPriorities),
    taskStatusOptions:         toOpts(data?.taskStatuses),
    assignmentStrategyOptions: toOpts(data?.assignmentStrategies),
    taskSkillOptions:          toOpts(data?.taskSkills),
    alertSeverityOptions:      toOpts(data?.alertSeverities),
    alertTypeOptions:          toOpts(data?.alertTypes),
    deadlineFilterOptions:     toOpts(data?.deadlineFilters),
    taskSortOrderOptions:            toOpts(data?.taskSortOrders),
    incidentStatusOptions:           toOpts(data?.incidentStatuses),
    incidentSeverityOptions:         toOpts(data?.incidentSeverities),
    incidentReportTypeOptions:       toOpts(data?.incidentReportTypes),
    incidentCategoryOptions:         toOpts(data?.incidentCategories),
    patientGenderOptions:            toOpts(data?.patientGenders),
    incidentOccurrenceStatusOptions: toOpts(data?.incidentOccurrenceStatuses),
    incidentNotifyStatusOptions:     toOpts(data?.incidentNotifyStatuses),
    accountRoleOptions:              toOpts(data?.accountRoles),
    accountStatusOptions:            toOpts(data?.accountStatuses),
    accountGenderOptions:            toOpts(data?.accountGenders),
  };
};
