/**
 * Real BFF API calls for Department endpoints.
 */

import type { Department } from '../../models/Department';
import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import type { BffDepartmentDto, BffDepartmentPagedResult, BffDepartmentStatsDto } from './responseModel';
import { mapBffDepartment } from './mapper';
import type {
  CreateDepartmentRequest,
  GetDepartmentsParams,
  ReorderItem,
  UpdateDepartmentRequest,
} from './requestModel';

export type DepartmentPagedResponse = {
  items:      Department[];
  totalCount: number;
  page:       number;
  pageSize:   number;
  totalPages: number;
};

export const departmentEndpoint = {
  getDepartments: async (params: GetDepartmentsParams = {}): Promise<DepartmentPagedResponse> => {
    const query = new URLSearchParams();
    if (params.includeInactive) query.set('includeInactive', 'true');
    if (params.search)          query.set('search', params.search);
    query.set('page',     String(params.page     ?? 1));
    query.set('pageSize', String(params.pageSize ?? 20));
    const res = await apiClient.get<BffResponse<BffDepartmentPagedResult>>(`/departments?${query}`);
    const data = unwrap(res);
    return {
      items:      data.items.map(mapBffDepartment),
      totalCount: data.totalCount,
      page:       data.page,
      pageSize:   data.pageSize,
      totalPages: data.totalPages,
    };
  },

  getDepartmentById: async (id: string): Promise<Department> => {
    const res = await apiClient.get<BffResponse<BffDepartmentDto>>(`/departments/${id}`);
    return mapBffDepartment(unwrap(res));
  },

  createDepartment: async (data: CreateDepartmentRequest): Promise<Department> => {
    const res = await apiClient.post<BffResponse<BffDepartmentDto>>('/departments', data);
    return mapBffDepartment(unwrap(res));
  },

  updateDepartment: async (id: string, data: UpdateDepartmentRequest): Promise<Department> => {
    const res = await apiClient.put<BffResponse<BffDepartmentDto>>(`/departments/${id}`, data);
    return mapBffDepartment(unwrap(res));
  },

  deactivateDepartment: async (id: string): Promise<void> => {
    await apiClient.delete(`/departments/${id}`);
  },

  reorderDepartments: async (items: ReorderItem[]): Promise<void> => {
    await apiClient.put('/departments/reorder', items);
  },

  // ── Stats ──────────────────────────────────────────────────────────────────

  /**
   * GET /departments/stats
   * Returns aggregate counts for all departments, independent of pagination.
   */
  getStats: async (): Promise<BffDepartmentStatsDto> => {
    const res = await apiClient.get<BffResponse<BffDepartmentStatsDto>>('/departments/stats');
    return unwrap(res);
  },
};
